import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;

public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
    List<String> validCoupons = new ArrayList<>();
    String[] businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    for (int i = 0; i < code.length; i++) {
        // Check if the coupon is valid
        if (isValidCoupon(code[i], businessLine[i], isActive[i])) {
            validCoupons.add(code[i]);
        }
    }

    // Sort the valid coupons according to the specified rules
    Collections.sort(validCoupons, new Comparator<String>() {
        @Override
        public int compare(String a, String b) {
            int aIndex = getBusinessIndex(a, code, businessLine);
            int bIndex = getBusinessIndex(b, code, businessLine);

            if (aIndex != bIndex) {
                return Integer.compare(aIndex, bIndex);
            } else {
                return a.compareTo(b);
            }
        }
    });

    return validCoupons.toArray(new String[0]);
}

private static boolean isValidCoupon(String code, String business, boolean isActive) {
    if (code == null || code.isEmpty()) {
        return false;
    }

    // Check code only contains alphanumeric and underscore
    for (char c : code.toCharArray()) {
        if (!Character.isLetterOrDigit(c) && c != '_') {
            return false;
        }
    }

    // Check business line is valid
    if (!business.equals("electronics") && !business.equals("grocery") 
        && !business.equals("pharmacy") && !business.equals("restaurant")) {
        return false;
    }

    // Check isActive
    return isActive;
}

private static int getBusinessIndex(String couponCode, String[] code, String[] businessLine) {
    for (int i = 0; i < code.length; i++) {
        if (code[i].equals(couponCode)) {
            String business = businessLine[i];
            switch (business) {
                case "electronics": return 0;
                case "grocery": return 1;
                case "pharmacy": return 2;
                case "restaurant": return 3;
                default: return -1;
            }
        }
    }
    return -1;
}
